  "sentences": [
    {
      "text": "可能是水龍頭的問題，所以一直漏水。",
      "pinyin": "Kěnéng shì shuǐlóngtóu de wèntí, suǒyǐ yīzhí lòushuǐ.",
      "pinyin_numeric": "ke3neng2 shi4 shui3long2tou2 de0 wen4ti2, suo3yi3 yi1zhi2 lou4shui3.",
      "translation_en": "It might be a problem with the faucet, so it keeps leaking.",
      "translation_ko": "수도꼭지 문제일 수도 있어서 계속 물이 새고 있어요."
    },
    {
      "text": "可能是馬桶的問題，排水很慢。",
      "pinyin": "Kěnéng shì mǎtǒng de wèntí, páishuǐ hěn màn.",
      "pinyin_numeric": "ke3neng2 shi4 ma3tong3 de0 wen4ti2, pai2shui3 hen3 man4.",
      "translation_en": "It might be a problem with the toilet; the drainage is very slow.",
      "translation_ko": "변기 문제일 수도 있어서 배수가 아주 느려요."
    },
    {
      "text": "可能是冷氣的問題，所以不冷。",
      "pinyin": "Kěnéng shì lěngqì de wèntí, suǒyǐ bù lěng.",
      "pinyin_numeric": "ke3neng2 shi4 leng3qi4 de0 wen4ti2, suo3yi3 bu4 leng3.",
      "translation_en": "It might be a problem with the air conditioner, so it's not cold.",
      "translation_ko": "에어컨 문제일 수도 있어서 시원하지 않아요."
    },
    {
      "text": "可能是熱水器的問題，所以沒有熱水。",
      "pinyin": "Kěnéng shì rèshuǐqì de wèntí, suǒyǐ méiyǒu rèshuǐ.",
      "pinyin_numeric": "ke3neng2 shi4 re4shui3qi4 de0 wen4ti2, suo3yi3 mei2you3 re4shui3.",
      "translation_en": "It might be a problem with the water heater, so there's no hot water.",
      "translation_ko": "온수기 문제일 수도 있어서 뜨거운 물이 나오지 않아요."
    },
    {
      "text": "可能是電線的問題，所以跳電了。",
      "pinyin": "Kěnéng shì diànxiàn de wèntí, suǒyǐ tiàodiàn le.",
      "pinyin_numeric": "ke3neng2 shi4 dian4xian4 de0 wen4ti2, suo3yi3 tiao4dian4 le0.",
      "translation_en": "It might be a problem with the wiring, so the power went out.",
      "translation_ko": "전선 문제일 수도 있어서 차단기가 내려갔어요."
    },
    {
      "text": "可能是門鎖的問題，所以打不開。",
      "pinyin": "Kěnéng shì ménsuǒ de wèntí, suǒyǐ dǎ bù kāi.",
      "pinyin_numeric": "ke3neng2 shi4 men2suo3 de0 wen4ti2, suo3yi3 da3 bu4 kai1.",
      "translation_en": "It might be a problem with the door lock, so it won't open.",
      "translation_ko": "도어락 문제일 수도 있어서 열리지 않아요."
    },
    {
      "text": "可能是窗戶的問題，所以有奇怪的聲音。",
      "pinyin": "Kěnéng shì chuānghù de wèntí, suǒyǐ yǒu qíguài de shēngyīn.",
      "pinyin_numeric": "ke3neng2 shi4 chuang1hu4 de0 wen4ti2, suo3yi3 you3 qi2guai4 de0 sheng1yin1.",
      "translation_en": "It might be a problem with the window, so there's a strange noise.",
      "translation_ko": "창문 문제일 수도 있어서 이상한 소리가 나요."
    },
    {
      "text": "可能是牆壁的問題，所以有裂縫。",
      "pinyin": "Kěnéng shì qiángbì de wèntí, suǒyǐ yǒu lièfèng.",
      "pinyin_numeric": "ke3neng2 shi4 qiang2bi4 de0 wen4ti2, suo3yi3 you3 lie4feng4.",
      "translation_en": "It might be a problem with the wall, so there's a crack.",
      "translation_ko": "벽 문제일 수도 있어서 금이 갔어요."
    },
    {
      "text": "可能是地板的問題，所以發霉了。",
      "pinyin": "Kěnéng shì dìbǎn de wèntí, suǒyǐ fāméi le.",
      "pinyin_numeric": "ke3neng2 shi4 di4ban3 de0 wen4ti2, suo3yi3 fa1mei2 le0.",
      "translation_en": "It might be a problem with the floor, so it's moldy.",
      "translation_ko": "바닥 문제일 수도 있어서 곰팡이가 생겼어요."
    },
    {
      "text": "可能是插座的問題，所以沒有電。",
      "pinyin": "Kěnéng shì chāzuò de wèntí, suǒyǐ méiyǒu diàn.",
      "pinyin_numeric": "ke3neng2 shi4 cha1zuo4 de0 wen4ti2, suo3yi3 mei2you3 dian4.",
      "translation_en": "It might be a problem with the outlet, so there's no electricity.",
      "translation_ko": "콘센트 문제일 수도 있어서 전기가 안 들어와요."
    }
  ]
}
